      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const service = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.query.projectId;
  if (!projectId) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Project ID is required' } });
  }
  const tasks = service.getTasksByProjectId(projectId);
  res.json({ tasks });
});

router.post('/', (req, res) => {
  const projectId = req.body.projectId;
  const { title } = req.body;
  if (!projectId || !title) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Project ID and Title are required' } });
  }
  const task = service.createTask(projectId, title);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.status(201).json({ task });
});

router.get('/:id', (req, res) => {
  const task = service.getTaskById(req.params.id);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
});

router.patch('/:id', (req, res) => {
  const { status } = req.body;
  if (!status) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Status is required' } });
  }
  const task = service.updateTask(req.params.id, status);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
});

module.exports = router;
